+    private static boolean isInvocationOnTargetType(CtInvocation<?> invocation, CtTypeReference<?> targetType) {
+        if (invocation.getTarget() == null || invocation.getTarget().getType() == null) {
+            return false;
+        }
+        CtTypeReference<?> actualType = invocation.getTarget().getType();
+        return actualType.isSubtypeOf(targetType) || targetType.isSubtypeOf(actualType);
+    }
